import { Portal } from '@ark-ui/react/portal';
import type { ToastOptions } from '@ark-ui/react/toast';
import {
  Toast as ToastPrimitive,
  Toaster as ToasterPrimitive,
  createToaster,
  useToastContext,
} from '@ark-ui/react/toast';
import { clsx } from 'clsx';
import type { ComponentProps, ComponentRef } from 'react';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import type { OverlayPortalProps } from '@/lib/moduix/overlayPortal';
import { CloseButton } from '../close-button';
import styles from './Toast.module.css';

const DEFAULT_CLOSE_TRIGGER_LABEL = 'Close toast';

type ToasterProps = Omit<ComponentProps<typeof ToasterPrimitive>, 'children'> &
  OverlayPortalProps & {
    children?: ComponentProps<typeof ToasterPrimitive>['children'];
  };

const Toaster = forwardRef<ComponentRef<typeof ToasterPrimitive>, ToasterProps>(function Toaster(
  { className, portalled = true, portalRef, ...props },
  ref,
) {
  return (
    <Portal disabled={!portalled} container={portalRef}>
      <ToasterPrimitive
        ref={ref}
        data-slot="toast-toaster"
        className={clsx(styles.toaster, normalizeClassName(className))}
        {...props}
      >
        {props.children ?? ((toast) => <DefaultToast toast={toast} />)}
      </ToasterPrimitive>
    </Portal>
  );
});

function DefaultToast({ toast }: { toast: ToastOptions }) {
  return (
    <ToastRoot key={toast.id}>
      {toast.title != null ? <ToastTitle /> : null}
      {toast.description != null ? <ToastDescription /> : null}
      {toast.action ? <ToastActionTrigger>{toast.action.label}</ToastActionTrigger> : null}
      {toast.closable !== false ? <ToastCloseTrigger /> : null}
    </ToastRoot>
  );
}

const ToastRoot = forwardRef<
  ComponentRef<typeof ToastPrimitive.Root>,
  ComponentProps<typeof ToastPrimitive.Root>
>(function ToastRoot({ className, ...props }, ref) {
  return (
    <ToastPrimitive.Root
      ref={ref}
      data-slot="toast-root"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const ToastTitle = forwardRef<
  ComponentRef<typeof ToastPrimitive.Title>,
  ComponentProps<typeof ToastPrimitive.Title>
>(function ToastTitle({ className, children, ...props }, ref) {
  const toast = useToastContext();

  return (
    <ToastPrimitive.Title
      ref={ref}
      data-slot="toast-title"
      className={clsx(styles.title, normalizeClassName(className))}
      {...props}
    >
      {children === undefined ? toast.title : children}
    </ToastPrimitive.Title>
  );
});

const ToastDescription = forwardRef<
  ComponentRef<typeof ToastPrimitive.Description>,
  ComponentProps<typeof ToastPrimitive.Description>
>(function ToastDescription({ className, children, ...props }, ref) {
  const toast = useToastContext();

  return (
    <ToastPrimitive.Description
      ref={ref}
      data-slot="toast-description"
      className={clsx(styles.description, normalizeClassName(className))}
      {...props}
    >
      {children === undefined ? toast.description : children}
    </ToastPrimitive.Description>
  );
});

const ToastActionTrigger = forwardRef<
  ComponentRef<typeof ToastPrimitive.ActionTrigger>,
  ComponentProps<typeof ToastPrimitive.ActionTrigger>
>(function ToastActionTrigger({ asChild, className, children, ...props }, ref) {
  return (
    <ToastPrimitive.ActionTrigger
      ref={ref}
      asChild={asChild}
      data-slot="toast-action-trigger"
      className={clsx(!asChild && styles.actionTrigger, normalizeClassName(className))}
      {...props}
    >
      {children}
    </ToastPrimitive.ActionTrigger>
  );
});

const ToastCloseTrigger = forwardRef<
  ComponentRef<typeof ToastPrimitive.CloseTrigger>,
  ComponentProps<typeof ToastPrimitive.CloseTrigger>
>(function ToastCloseTrigger(
  { asChild, className, children, 'aria-label': ariaLabel = DEFAULT_CLOSE_TRIGGER_LABEL, ...props },
  ref,
) {
  if (asChild) {
    return (
      <ToastPrimitive.CloseTrigger
        ref={ref}
        asChild
        data-slot="toast-close-trigger"
        aria-label={ariaLabel}
        className={normalizeClassName(className)}
        {...props}
      >
        {children}
      </ToastPrimitive.CloseTrigger>
    );
  }

  return (
    <ToastPrimitive.CloseTrigger asChild>
      <CloseButton.Root
        ref={ref}
        data-slot="toast-close-trigger"
        aria-label={ariaLabel}
        className={clsx(styles.closeTrigger, normalizeClassName(className))}
        {...props}
      >
        {children}
      </CloseButton.Root>
    </ToastPrimitive.CloseTrigger>
  );
});

const Toast = Object.assign(ToastRoot, {
  Root: ToastRoot,
  Title: ToastTitle,
  Description: ToastDescription,
  ActionTrigger: ToastActionTrigger,
  CloseTrigger: ToastCloseTrigger,
  Toaster,
});

export { Toast, Toaster, createToaster };

@layer moduix.components {
  .toaster {
    z-index: var(--moduix-toast-z-index, var(--moduix-z-toast));
  }

  .root {
    --moduix-toast-trigger-bg-default: transparent;
    --moduix-toast-trigger-bg-hover-default: var(--moduix-color-accent);
    --moduix-toast-trigger-border-color-default: var(--moduix-color-border);
    --moduix-toast-trigger-color-default: var(--moduix-color-foreground);
    --moduix-toast-trigger-focus-ring-color-default: var(--moduix-color-ring);
    box-sizing: border-box;
    display: grid;
    width: var(--moduix-toast-width, 20rem);
    max-width: calc(100vw - (var(--moduix-toast-viewport-inset, var(--moduix-spacing-4)) * 2));
    min-height: var(--moduix-toast-min-height, 0);
    align-items: start;
    gap: var(--moduix-toast-content-gap, var(--moduix-spacing-1));
    border: var(--moduix-toast-border-width, var(--moduix-border-width-sm)) solid
      var(
        --moduix-toast-border-color,
        var(--moduix-toast-border-color-default, var(--moduix-color-border))
      );
    border-radius: var(--moduix-toast-radius, var(--moduix-radius-lg));
    background-color: var(
      --moduix-toast-bg,
      var(--moduix-toast-bg-default, var(--moduix-color-popover))
    );
    color: var(
      --moduix-toast-color,
      var(--moduix-toast-color-default, var(--moduix-color-popover-foreground))
    );
    background-clip: padding-box;
    box-shadow: var(--moduix-toast-shadow, var(--moduix-shadow-lg));
    padding: var(--moduix-toast-padding, var(--moduix-spacing-4));
    padding-inline-end: calc(
      var(--moduix-toast-padding, var(--moduix-spacing-4)) +
        var(--moduix-toast-close-size, var(--moduix-spacing-7))
    );
    pointer-events: auto;
    user-select: none;
    translate: var(--x) var(--y);
    scale: var(--scale);
    z-index: var(--z-index);
    height: var(--height);
    opacity: var(--opacity);
    will-change: translate, opacity, scale;
    transition:
      translate var(--moduix-toast-transition, var(--moduix-duration-slow)),
      scale var(--moduix-toast-transition, var(--moduix-duration-slow)),
      opacity var(--moduix-toast-transition, var(--moduix-duration-slow)),
      height var(--moduix-toast-transition, var(--moduix-duration-slow)),
      box-shadow var(--moduix-transition-fast);
    transition-timing-function: cubic-bezier(0.21, 1.02, 0.73, 1);

    &[data-state='closed'] {
      transition:
        translate var(--moduix-toast-transition-out, var(--moduix-duration-slow)),
        scale var(--moduix-toast-transition-out, var(--moduix-duration-slow)),
        opacity var(--moduix-toast-opacity-transition-out, var(--moduix-duration-normal));
      transition-timing-function: cubic-bezier(0.06, 0.71, 0.55, 1);
    }

    &[data-type='success'] {
      --moduix-toast-bg-default: color-mix(
        in oklab,
        var(--moduix-color-success) 10%,
        var(--moduix-color-background)
      );
      --moduix-toast-border-color-default: color-mix(
        in oklab,
        var(--moduix-color-success) 34%,
        transparent
      );
      --moduix-toast-color-default: var(--moduix-color-foreground);
      --moduix-toast-description-color-default: var(--moduix-color-muted-foreground);
    }

    &[data-type='warning'] {
      --moduix-toast-bg-default: color-mix(
        in oklab,
        var(--moduix-color-warning) 13%,
        var(--moduix-color-background)
      );
      --moduix-toast-border-color-default: color-mix(
        in oklab,
        var(--moduix-color-warning) 38%,
        transparent
      );
      --moduix-toast-color-default: var(--moduix-color-foreground);
      --moduix-toast-description-color-default: var(--moduix-color-muted-foreground);
    }

    &[data-type='destructive'],
    &[data-type='error'] {
      --moduix-toast-bg-default: color-mix(
        in oklab,
        var(--moduix-color-destructive) 9%,
        var(--moduix-color-background)
      );
      --moduix-toast-border-color-default: color-mix(
        in oklab,
        var(--moduix-color-destructive) 35%,
        transparent
      );
      --moduix-toast-color-default: var(--moduix-color-foreground);
      --moduix-toast-description-color-default: var(--moduix-color-muted-foreground);
    }
  }

  .title {
    display: flex;
    align-items: center;
    gap: var(--moduix-toast-title-gap, var(--moduix-spacing-2));
    margin: 0;
    color: inherit;
    font-size: var(--moduix-toast-title-font-size, var(--moduix-text-sm));
    font-weight: var(--moduix-toast-title-font-weight, var(--moduix-weight-semibold));
    line-height: var(--moduix-toast-title-line-height, var(--moduix-line-height-text-sm));
  }

  .description {
    margin: 0;
    color: var(
      --moduix-toast-description-color,
      var(--moduix-toast-description-color-default, var(--moduix-color-muted-foreground))
    );
    font-size: var(--moduix-toast-description-font-size, var(--moduix-text-sm));
    line-height: var(--moduix-toast-description-line-height, var(--moduix-line-height-text-sm));
  }

  .actionTrigger {
    display: inline-flex;
    width: max-content;
    align-items: center;
    justify-content: center;
    gap: var(--moduix-toast-action-gap, var(--moduix-spacing-2));
    min-height: var(--moduix-toast-action-min-height, var(--moduix-size-xs));
    margin-top: var(--moduix-toast-action-margin-top, var(--moduix-spacing-2));
    border: var(
        --moduix-toast-action-border-width,
        var(--moduix-toast-border-width, var(--moduix-border-width-sm))
      )
      solid
      var(--moduix-toast-action-border-color, var(--moduix-toast-trigger-border-color-default));
    border-radius: var(--moduix-toast-action-radius, var(--moduix-radius-sm));
    background: var(--moduix-toast-action-bg, var(--moduix-toast-trigger-bg-default));
    color: var(--moduix-toast-action-color, var(--moduix-toast-trigger-color-default));
    padding: var(--moduix-toast-action-padding-y, var(--moduix-spacing-1))
      var(--moduix-toast-action-padding-x, var(--moduix-spacing-2));
    font: inherit;
    font-size: var(--moduix-toast-action-font-size, var(--moduix-text-xs));
    font-weight: var(--moduix-toast-action-font-weight, var(--moduix-weight-medium));
    line-height: var(--moduix-toast-action-line-height, var(--moduix-line-height-text-xs));
    cursor: pointer;
    user-select: none;
    white-space: nowrap;
    transition:
      background var(--moduix-transition-fast),
      border-color var(--moduix-transition-fast),
      color var(--moduix-transition-fast);

    &:hover {
      background: var(--moduix-toast-action-bg-hover, var(--moduix-toast-trigger-bg-hover-default));
    }

    &:focus-visible {
      outline: var(
          --moduix-toast-focus-ring-width,
          var(
            --moduix-toast-action-border-width,
            var(--moduix-focus-ring-inset-width, var(--moduix-border-width-sm))
          )
        )
        solid
        var(--moduix-toast-focus-ring-color, var(--moduix-toast-trigger-focus-ring-color-default));
      outline-offset: var(--moduix-toast-focus-ring-offset, 0);
    }
  }

  .closeTrigger {
    position: absolute;
    inset-block-start: var(--moduix-toast-close-offset-top, var(--moduix-spacing-2));
    inset-inline-end: var(--moduix-toast-close-offset-right, var(--moduix-spacing-2));
    --moduix-close-button-size: var(--moduix-toast-close-size, var(--moduix-spacing-7));
    --moduix-close-button-icon-size: var(--moduix-toast-close-icon-size, var(--moduix-spacing-3));
    --moduix-close-button-radius: var(--moduix-toast-close-radius, var(--moduix-radius-sm));
    --moduix-close-button-bg: var(--moduix-toast-close-bg, transparent);
    --moduix-close-button-bg-hover: var(--moduix-toast-close-bg-hover, var(--moduix-color-muted));
    --moduix-close-button-color: var(
      --moduix-toast-close-color,
      var(--moduix-color-muted-foreground)
    );
    --moduix-close-button-color-hover: var(
      --moduix-toast-close-color-hover,
      var(--moduix-color-foreground)
    );
    --moduix-close-button-focus-ring-color: var(
      --moduix-toast-focus-ring-color,
      var(--moduix-color-ring)
    );
    --moduix-close-button-focus-ring-offset: var(
      --moduix-toast-close-focus-ring-offset,
      var(--moduix-focus-ring-offset)
    );
    --moduix-close-button-focus-ring-width: var(
      --moduix-toast-close-focus-ring-width,
      var(--moduix-focus-ring-width, var(--moduix-border-width-md))
    );
    --moduix-close-button-transition: var(
      --moduix-toast-close-transition,
      var(--moduix-transition-default)
    );
  }

  @media (max-width: 40rem) {
    .toaster {
      width: 100%;
    }

    .root {
      inset-inline: 0;
      width: calc(100% - (var(--gap) * 2));
      max-width: none;
    }
  }
}
